<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Http\Requests\Payroll\PayrollReasonRequest; use App\Http\Requests\Payroll\RecordPayrollPaymentRequest; use App\Models\Finance\CashAccount; use App\Models\Payroll\PayrollPayment; use App\Models\Payroll\PayrollRun; use App\Services\Payroll\PayrollPaymentService; use Illuminate\Http\RedirectResponse; use Illuminate\View\View; class PayrollPaymentController extends Controller{public function index():View{return view('payroll.payments.index',['title'=>'Pembayaran Gaji','payments'=>PayrollPayment::with('run')->latest()->paginate(15),'runs'=>PayrollRun::whereIn('status',['final','partially_paid'])->get(),'cashAccounts'=>CashAccount::where('is_active',true)->get()]);} public function store(RecordPayrollPaymentRequest $r,PayrollRun $run,PayrollPaymentService $s):RedirectResponse{$s->record($run,$r->validated(),$r->user()->id);return back()->with('status','Pembayaran gaji dicatat dan diposting ke Keuangan Operasional.');} public function cancel(PayrollReasonRequest $r,PayrollPayment $payment,PayrollPaymentService $s):RedirectResponse{$s->cancel($payment,$r->string('reason')->toString(),$r->user()->id);return back()->with('status','Pembayaran gaji dibatalkan.');}}
